SELECT fund_id, SUM(dollar_held) AS total_investment
FROM fund_transactions
GROUP BY fund_id;

SELECT *
FROM funds
ORDER BY fund_name ASC;

SELECT analysis_id, fund_id, analysis_date, risk_score, risk_factors, confidence_level
FROM risk_analysis
ORDER BY analysis_date ASC;

SELECT DISTINCT users.user_name
FROM users
INNER JOIN security_logs ON users.user_id = security_logs.user_id;

SELECT fund_name
FROM funds
WHERE fund_type = 'hybrid' AND fund_currency = 'USD';
